1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	export function quote(customer: Customer, items: Item[]): number {
22	  const basePremium = items.reduce(
23	    (sum, item) => sum + (BASE_PREMIUMS[item.type] * 11) / 10,
24	    0,
25	  );
26	  return Math.ceil(basePremium) + PROCESSING_FEE;
27	}
